const rpcAddress: ZodType<Uint8Array> = conditionalUnionType(
  [
    [
      (data) => Buffer.isBuffer(data) && data.length === ADDRESS_LENGTH_BYTES,
      z.instanceof(Uint8Array),
    ],
    [isAddress, z.string()],
  ],
  "Expected a Buffer with correct length or a valid RPC address string",
).transform((v) => (typeof v === "string" ? hexStringToBytes(v) : v));

const rpcHash: ZodType<Uint8Array> = conditionalUnionType(
  [
    [
      (data) => Buffer.isBuffer(data) && data.length === HASH_LENGTH_BYTES,
      z.instanceof(Uint8Array),
    ],
    [isHash, z.string()],
  ],
  "Expected a Buffer with the correct length or a valid RPC hash string",
).transform((v) =>
  typeof v === "string" ? Buffer.from(hexStringToBytes(v)) : v,
);

const rpcParity: ZodType<Buffer> = conditionalUnionType(
  [
    [
      (data) => Buffer.isBuffer(data) && data.length === PARITY_LENGTH_BYTES,
      z.instanceof(Uint8Array),
    ],
    [isRpcParityString, z.string()],
  ],
  "Expected a Buffer or valid parity string",
).transform((v) =>
  typeof v === "string" ? Buffer.from(hexStringToBytes(v)) : v,
);

return new Promise((accept, reject) => {
    const sock = net.createConnection(port);
    sock.once("connect", () => {
        sock.end();
        accept(false);
    });
    sock.once("error", (e: NodeJS.ErrnoException) => {
        sock.destroy();
        if (e.code === "ECONNREFUSED") {
            accept(true);
        } else {
            reject(e);
        }
    });
});

const contains = (circuitsRoot: string, pathList: string[], source: any) => {
  const isSubPath = (parent: string, child: string) => {
    const parentTokens = parent.split(/\\|\//).filter((i) => i.length);
    const childTokens = child.split(/\\|\//).filter((i) => i.length);

    return parentTokens.every((t, i) => childTokens[i] === t);
  };

  return pathList.some((p: any) => {
    return isSubPath(getNormalizedFullPath(circuitsRoot, p), source);
  });
};

for (const fnDef of findAll('FunctionDefinition', contractDef, (node) => skipCheck('constructor', node))) {
    if (fnDef.kind === 'constructor' && ((fnDef.body?.statements?.length ?? 0) > 0 || fnDef.modifiers.length > 0)) {
        yield {
            kind: 'constructor',
            contract: contractDef.name,
            src: decodeSrc(fnDef),
        };
    }
}

for (const fnCall of findAll(
    'FunctionCall',
    contractOrFunctionDef,
    (node) => skipCheck(opcode.kind, node) || (scope === 'inherited' && isInternalFunction(node)),
)) {
    const fn = fnCall.expression;
    if (fn.typeDescriptions.typeIdentifier?.match(opcode.pattern)) {
        yield {
            kind: opcode.kind,
            src: decodeSrc(fnCall),
        };
    }
}

